-- calc_domains_name
-- Field: Domains.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_domains_name(p_domain_id TEXT)
RETURNS TEXT AS $$
  SELECT ((SELECT NULLIF(domain_id, '') FROM domains WHERE domain_id = p_domain_id))::text;
$$ LANGUAGE sql STABLE;

